import numpy as np
from scipy import sparse
from scipy.sparse import csgraph


class Solver:
    def solve(self, problem, **kwargs) -> dict:
        try:
            graph_csr = sparse.csr_matrix(
                (problem["data"], problem["indices"], problem["indptr"]),
                shape=problem["shape"],
            )
            source_indices = problem["source_indices"]
            if not isinstance(source_indices, list) or not source_indices:
                raise ValueError("source_indices missing or empty")
        except Exception as e:
            print(f"Failed to reconstruct input from problem data: {e}")
            return {"distances": []}

        try:
            dist_matrix = csgraph.dijkstra(
                csgraph=graph_csr, directed=False, indices=source_indices
            )
        except Exception as e:
            print(f"scipy.sparse.csgraph.dijkstra failed: {e}")
            return {"distances": []}

        if dist_matrix.ndim == 1:
            dist_matrix_list = [[(None if np.isinf(d) else d) for d in dist_matrix]]
        else:
            dist_matrix_list = [
                [(None if np.isinf(d) else d) for d in row] for row in dist_matrix
            ]

        return {"distances": dist_matrix_list}
